// // This module implements a synchronous dual-port RAM with a memory depth of 2048 words and a data width of 8 bits. It supports concurrent read and write operations enabled by separate read and write enable signals (rce and wce). On the falling edge of the clock, if the read enable is active, it outputs the content of the memory address specified by the read address input (ra) onto the read data output (rq). If the write enable is active, it stores the input data (wd) into the memory at the address specified by the write address input (wa). This design is ideal for applications needing quick and effective data storage and retrieval.
module top_module(
    input clk,
    input rce,
    input [10:0] ra,
    output reg [7:0] rq,
    input wce,
    input [10:0] wa,
    input [7:0] wd
);parameter AWIDTH = 11;
parameter DWIDTH = 8;

reg [7:0] mem [0:2047];

always @(posedge clk) begin
    if (rce) begin
        rq <= mem[ra];
    end
    if (wce) begin
        mem[wa] <= wd;
    end
end

endmodule
